<script setup lang="ts">
import type { PublicProductDetail } from "@moecraft/shared";
const route = useRoute();
const { request, mediaUrl, money } = useStorefrontCatalog();
const id = String(route.params.id);
const { data: product, pending, error } = await useAsyncData(`product-${id}`, () => request<PublicProductDetail>(`/catalog/products/${encodeURIComponent(id)}`));
const selectedSkuId = ref("");
const selectedMediaId = ref("");
watch(product, (value) => { if (!value) return; selectedSkuId.value = value.skus.find((sku) => sku.inStock)?.id ?? value.skus[0]?.id ?? ""; selectedMediaId.value = value.media.find((media) => media.kind === "IMAGE" && media.isCover)?.id ?? value.media.find((media) => media.kind === "IMAGE")?.id ?? ""; }, { immediate: true });
const selectedSku = computed(() => product.value?.skus.find((sku) => sku.id === selectedSkuId.value) ?? product.value?.skus[0]);
const selectedMedia = computed(() => product.value?.media.find((media) => media.id === selectedMediaId.value));
const images = computed(() => product.value?.media.filter((media) => media.kind === "IMAGE") ?? []);
function date(value: string | null) { return value ? new Intl.DateTimeFormat("zh-CN", { dateStyle: "long" }).format(new Date(value)) : "待商家确认"; }
useSeoMeta({ title: () => product.value ? `${product.value.titleZhCn} - MoeCraft` : "商品详情 - MoeCraft", description: () => product.value?.descriptionZhCn?.slice(0, 150) ?? "MoeCraft 手办商品详情", ogTitle: () => product.value?.titleZhCn, ogDescription: () => product.value?.descriptionZhCn ?? undefined, ogImage: () => images.value[0] ? mediaUrl(images.value[0].fileId) : undefined });
useHead(() => product.value ? { script: [{ type: "application/ld+json", textContent: JSON.stringify({ "@context": "https://schema.org", "@type": "Product", name: product.value.titleZhCn, description: product.value.descriptionZhCn, image: images.value.map((item) => mediaUrl(item.fileId)), brand: product.value.brand ? { "@type": "Brand", name: product.value.brand.nameZhCn } : undefined, sku: selectedSku.value?.code, offers: selectedSku.value ? { "@type": "Offer", priceCurrency: selectedSku.value.currency, price: selectedSku.value.priceAmount / 100, availability: selectedSku.value.inStock ? "https://schema.org/InStock" : "https://schema.org/OutOfStock", seller: { "@type": "Organization", name: product.value.store.name } } : undefined }) }] } : {});
</script>

<template>
  <div class="product-page">
    <StorefrontHeader />
    <main v-if="pending" class="loading"><div /><section><i v-for="n in 6" :key="n" /></section></main>
    <main v-else-if="error || !product" class="state"><h1>商品不存在或已下架</h1><NuxtLink to="/catalog">返回商品目录</NuxtLink></main>
    <main v-else>
      <nav class="crumb"><NuxtLink to="/catalog">商品目录</NuxtLink><span>/</span><NuxtLink v-if="product.category" :to="`/categories/${product.category.slug}`">{{ product.category.nameZhCn }}</NuxtLink><span>/</span><b>{{ product.titleZhCn }}</b></nav>
      <section class="product-main">
        <div class="gallery">
          <div class="primary"><img v-if="selectedMedia" :src="mediaUrl(selectedMedia.fileId)" :alt="selectedMedia.altZhCn || product.titleZhCn"><div v-else class="fallback"><b>M</b><span>MOECRAFT</span></div></div>
          <div v-if="images.length > 1" class="thumbs"><button v-for="image in images" :key="image.id" type="button" :class="{ active: image.id === selectedMediaId }" :aria-label="image.altZhCn || product.titleZhCn" @click="selectedMediaId = image.id"><img :src="mediaUrl(image.fileId)" :alt="image.altZhCn || ''"></button></div>
        </div>
        <div class="summary">
          <div class="taxonomy"><NuxtLink v-if="product.franchise" :to="`/franchises/${product.franchise.slug}`">{{ product.franchise.nameZhCn }}</NuxtLink><span>{{ product.saleType === 'PREORDER' ? '预售' : '现货' }}</span></div>
          <h1>{{ product.titleZhCn }}</h1><p class="english">{{ product.titleEnUs }}</p>
          <div class="price">{{ money(selectedSku?.priceAmount ?? null, selectedSku?.currency) }}</div>
          <section class="sku-picker"><header><b>选择规格</b><span>{{ selectedSku?.inStock ? `可售 ${selectedSku.available}` : '暂时无货' }}</span></header><div><button v-for="sku in product.skus" :key="sku.id" type="button" :class="{ active: sku.id === selectedSkuId }" @click="selectedSkuId = sku.id"><b>{{ sku.nameZhCn }}</b><small>{{ money(sku.priceAmount, sku.currency) }}</small><i>{{ sku.inStock ? `${sku.available} 件` : '售罄' }}</i></button></div></section>
          <section v-if="product.saleType === 'PREORDER'" class="notice"><b>预售信息</b><p>{{ product.presaleNotice }}</p><dl><dt>预计发货</dt><dd>{{ date(product.shippingWindowStart) }} 至 {{ date(product.shippingWindowEnd) }}</dd></dl></section>
          <div class="store-link"><div><img v-if="product.store.logoFileId" :src="mediaUrl(product.store.logoFileId)" :alt="product.store.name"><span v-else>{{ product.store.name.slice(0, 1) }}</span><p><b>{{ product.store.name }}</b><small>平台审核商家</small></p></div><NuxtLink :to="`/stores/${product.store.slug}`">进入店铺</NuxtLink></div>
        </div>
      </section>
      <section class="details">
        <article><small>PRODUCT STORY</small><h2>商品介绍</h2><p>{{ product.descriptionZhCn || '商家暂未补充商品介绍。' }}</p><p v-if="product.descriptionEnUs" class="secondary">{{ product.descriptionEnUs }}</p></article>
        <aside><div><b>商品信息</b><dl><template v-if="product.material"><dt>材质</dt><dd>{{ product.material }}</dd></template><template v-if="product.scale"><dt>比例</dt><dd>{{ product.scale }}</dd></template><template v-if="product.manufacturer"><dt>厂商</dt><dd>{{ product.manufacturer }}</dd></template><template v-if="product.character"><dt>角色</dt><dd>{{ product.character.nameZhCn }}</dd></template></dl></div><div><b>正版与版权</b><p>{{ product.copyrightNotice || '版权与授权信息由商家提交并经平台审核。' }}</p></div><div><b>售后服务</b><p>{{ product.afterSalesSummary || '签收后如发现商品问题，请保留完整包装并联系店铺客服。' }}</p><a v-if="product.store.customerServiceEmail" :href="`mailto:${product.store.customerServiceEmail}`">{{ product.store.customerServiceEmail }}</a></div></aside>
      </section>
    </main>
    <StorefrontFooter />
  </div>
</template>

