mplate-columns:1fr 1fr;gap:40px}.loading>div{aspect-ratio:1;background:#e5e8ec}.loading section{display:grid;align-content:start;gap:12px}.loading i{height:50px;background:#e5e8ec;animation:pulse 1s infinite alternate}.state{display:grid;min-height:calc(100vh - 170px);place-content:center;place-items:center}.state a{color:#d14b6b}@keyframes pulse{to{opacity:.5}}@media(max-width:850px){.product-main,.details{grid-template-columns:1fr}.summary{padding-top:0}.details{gap:20px}}@media(max-width:520px){.product-page>main{padding-inline:16px}.product-main{gap:24px}.summary>h1{font-size:24px}.sku-picker>div{grid-template-columns:1fr}.details{padding-top:35px}.notice dl{display:grid;gap:5px}}
